import React,{useState}from"react";import{Headphones,Mail,Phone}from"lucide-react";import{publicAPI}from"../../services/api.js";import{useToast}from"../../components/ui/Toast.jsx";import Modal from"../../components/ui/Modal.jsx";import{TextArea,TextInput}from"../../components/ui/Form.jsx";import{CardPanel,PageHeader}from"../../components/ui/PortalUI.jsx";
export default function VendorSupportPage(){const{showToast}=useToast();const[open,setOpen]=useState(false);const[form,setForm]=useState({full_name:"",email:"",mobile:"",message:""});const send=async(e)=>{e.preventDefault();try{await publicAPI.contact(form);showToast("Support message sent");setOpen(false)}catch(err){showToast(err.message,"error")}};return <div className="page-wrap"><PageHeader icon={Headphones} title="Help & Support" subtitle="We are here to help you manage leads, quotes and payments." action={<button className="red-btn" onClick={()=>setOpen(true)}>Start Live Chat</button>}/><div className="content-grid-wide"><CardPanel title="Popular Help Topics"><div className="progress-list">{["How do I get new leads?","How do I submit a quote?","How do payments work?","How do I update documents?","How do I contact support?"].map(t=><button className="chat-item" key={t}><Headphones size={16}/><div><b>{t}</b><p>View answer</p></div></button>)}</div></CardPanel><CardPanel title="Need More Help?"><DetailsGrid rows={[["Phone",<><Phone size={14}/>020 8064 1234</>],["Email",<><Mail size={14}/>support@anqmovers.co.uk</>],["Support", "24/7 vendor support"]]}/><div className="modal-actions"><button className="red-btn" onClick={()=>setOpen(true)}>Contact Support</button></div></CardPanel></div><Modal open={open} title="Contact Support" onClose={()=>setOpen(false)}><form onSubmit={send}><TextInput label="Full Name" value={form.full_name} onChange={v=>setForm({...form,full_name:v})}/><TextInput label="Email" value={form.email} onChange={v=>setForm({...form,email:v})}/><TextInput label="Mobile" value={form.mobile} onChange={v=>setForm({...form,mobile:v})}/><TextArea label="Message" value={form.message} onChange={v=>setForm({...form,message:v})}/><div className="modal-actions"><button type="button" className="outline-btn" onClick={()=>setOpen(false)}>Cancel</button><button className="red-btn">Send</button></div></form></Modal></div>}
